{"code": """"Build both fun4me and alejandro standalone apps from PAB data"""
from hermes_tools import write_file, terminal
import json, shutil, os

def create_app(src_name: str, dest: str, locales: list[str], domain: str):
    """Create a standalone Next.js app from PAB site data with minimal template"""
    if os.path.exists(dest):
        shutil.rmtree(dest)

    # Copy content
    pab = f"/tmp/pab-work/sites/{src_name}"
    os.makedirs(f"{dest}/content", exist_ok=True)
    for loc in locales:
        f = f"{pab}/content/{loc}.json"
        if os.path.exists(f):
            shutil.copy2(f, f"{dest}/content/{loc}.json")

    # Copy images
    img_src = f"{pab}/images"
    if os.path.exists(img_src):
        for root, dirs, files in os.walk(img_src):
            for f in files:
                rel = os.path.relpath(root, img_src)
                os.makedirs(f"{dest}/public/images/{rel}", exist_ok=True)
                shutil.copy2(os.path.join(root, f), f"{dest}/public/images/{rel}")

    # Copy docs/blog
    for d in ["docs", "blog", "legal", "pages"]:
        s = f"{pab}/{d}"
        if os.path.exists(s):
            shutil.copytree(s, f"{dest}/{d}", dirs_exist_ok=True)

    # Write package.json
    write_file(f"{dest}/package.json", json.dumps({
        "name": src_name.replace("-", "_"),
        "version": "1.0.0", "private": True,
        "scripts": {"dev": "next dev", "build": "next build", "start": "next start"},
        "dependencies": {"next": "^15.3.6", "react": "^19.1.0", "react-dom": "^19.1.0"}
    }, indent=2))

    # Write next.config.ts
    write_file(f"{dest}/next.config.ts", f"""import type {{ NextConfig }} from "next"
const config: NextConfig = {{
  images: {{ unoptimized: true }},
  output: "standalone",
  async redirects() {{
    return [{{ source: "/s/:path*", destination: "/", permanent: true }}]
  }},
}}
export default config
""")

    # Write globals.css
    write_file(f"{dest}/app/globals.css", """@import "tailwindcss";
@theme {
  --color-primary: #1B2A4A;
  --color-primary-foreground: #FFFFFF;
  --color-secondary: #C9A96E;
  --color-secondary-foreground: #1B2A4A;
  --color-background: #FAFAFA;
  --color-foreground: #1B2A4A;
  --color-muted-foreground: #6B7280;
  --color-surface: #FFFFFF;
  --color-surface-light: #F3F4F6;
  --color-border: #E5E7EB;
}
""")

    # Write layout.tsx
    write_file(f"{dest}/app/layout.tsx", f"""import type {{ Metadata }} from "next"
import "./globals.css"
export const metadata: Metadata = {{
  title: "{src_name.replace('-', ' ').title()}",
  description: "Standalone site",
}}
export default function RootLayout({{ children }}: {{ children: React.ReactNode }}) {{
  return <html lang="{locales[0]}"><body className="antialiased">{{children}}</body></html>
}}
""")

    # Write page.tsx (simple homepage)
    write_file(f"{dest}/app/page.tsx", """export default function Home() {
  return (
    <main className="flex min-h-screen flex-col items-center justify-center p-8 text-center bg-background">
      <h1 className="text-4xl font-bold text-foreground">Under Construction</h1>
      <p className="mt-4 text-muted-foreground max-w-md">This site is being built. Check back soon.</p>
    </main>
  )
}
""")

    # Dockerfile
    write_file(f"{dest}/Dockerfile", f"""FROM node:20-alpine AS builder
WORKDIR /app
COPY package.json ./
RUN npm install --legacy-peer-deps
COPY . .
RUN npm run build

FROM node:20-alpine AS runner
WORKDIR /app
COPY --from=builder /app/.next/standalone ./
COPY --from=builder /app/public ./public
COPY --from=builder /app/.next/static ./.next/static
EXPOSE 3000
CMD ["node", "server.js"]
""")

    # docker-compose.yml
    write_file(f"{dest}/docker-compose.yml", f"""version: '3.8'
services:
  web:
    build: .
    image: {src_name}:prod
    ports: ["3000"]
    networks: ["agent-net"]
    deploy:
      mode: replicated
      replicas: 2
      labels:
        - "traefik.enable=true"
        - "traefik.http.routers.{src_name.replace('-','_')}.entrypoints=websecure"
        - "traefik.http.routers.{src_name.replace('-','_')}.rule=Host(`{domain}.paragu-ai.com`)"
        - "traefik.http.routers.{src_name.replace('-','_')}.tls=true"
        - "traefik.http.routers.{src_name.replace('-','_')}.tls.certresolver=letsencryptresolver"
        - "traefik.http.services.{src_name.replace('-','_')}.loadbalancer.server.port=3000"
        - "traefik.docker.network=agent-net"
networks:
  agent-net:
    external: true
""")

    # Install + build
    terminal(f"cd {dest} && npm install --legacy-peer-deps 2>&1 | tail -1", timeout=60)
    print(f"  {src_name}: npm install done")
    r = terminal(f"cd {dest} && npm run build 2>&1 | tail -3", timeout=120)
    print(f"  {src_name}: {r['output'][:50]}")

    # Deploy
    r = terminal(f"cd {dest} && docker stack deploy -c docker-compose.yml {src_name.replace('-','_')} --detach=false 2>&1 | tail -2", timeout=30)
    print(f"  {src_name}: {r['output'][:100]}")

    # Push to GitHub
    terminal(f"cd {dest} && git init && git add -A && git commit -m 'feat: initial {src_name} standalone site' && git branch -M main && gh repo create Ai-Whisperers/{src_name} --public --push --source=. --description '{src_name} standalone site' 2>&1 | tail -3", timeout=20)
    print(f"  {src_name}: github pushed")

# Build fun4me
create_app("fun4me", "/tmp/fun4me-app", ["es"], "fun4me")
print("Fun4Me: Docker deployed at fun4me.paragu-ai.com -- add A record")

# Build alejandro-villamayor  
create_app("alejandro-villamayor", "/tmp/alejandro-app", ["es", "en"], "alejandro-villamayor")
print("Alejandro: Docker deployed at alejandro-villamayor.paragu-ai.com -- add A record")
"}

